import{_ as i,o as s,c as t,aa as a}from"./chunks/framework.vXJbu8_U.js";const k=JSON.parse('{"title":"Введение","description":"","frontmatter":{},"headers":[],"relativePath":"ru/guide/introduction.md","filePath":"ru/guide/introduction.md","lastUpdated":1781017578000}'),r={name:"ru/guide/introduction.md"};function o(n,e,d,c,l,h){return s(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="введение" tabindex="-1">Введение <a class="header-anchor" href="#введение" aria-label="Permalink to &quot;Введение&quot;">​</a></h1><h2 id="проблема" tabindex="-1">Проблема <a class="header-anchor" href="#проблема" aria-label="Permalink to &quot;Проблема&quot;">​</a></h2><p>Почти каждое приложение водит один и тот же хоровод вокруг данных: запустить запрос, отследить загрузку, поймать ошибку, показать результат. Дальше вмешивается реальность — пользователь кликает дважды, второй запрос обгоняет первый, ответ уже устарел, хочется ретрай, не хочется перезапрашивать только что полученное, и желательно, чтобы всё это не жило внутри компонента.</p><p>Руками это превращается в болото из <code>useState</code>/<code>useEffect</code>, гонок и логики, приваренной к вью. effector прекрасно решает часть про <em>состояние</em> — событиями, сторами и эффектами. <strong>effector-refetch</strong> берёт на себя часть про <em>получение данных</em> поверх него.</p><h2 id="идея-строимся-на-реальных-эффектах" tabindex="-1">Идея: строимся на реальных эффектах <a class="header-anchor" href="#идея-строимся-на-реальных-эффектах" aria-label="Permalink to &quot;Идея: строимся на реальных эффектах&quot;">​</a></h2><p>Ключевое решение простое: <strong>ваш эффект — это единица работы.</strong></p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> fetchUserFx</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> createEffect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">((</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> api.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">user</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(id));</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> userQuery</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> createQuery</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ effect: fetchUserFx });</span></span></code></pre></div><p><code>userQuery</code> — тонкая реактивная обёртка вокруг <code>fetchUserFx</code>. Она добавляет <code>$data</code>, <code>$error</code>, <code>$status</code>, <code>$pending</code>, события жизненного цикла, retry, cache и concurrency — но эффект под ней остаётся вашим: виден в devtools, композируется через <code>attach</code>, дружит с fork для SSR и тестов. Ничего не спрятано в приватном «исполнителе».</p><p>В этом отличие от «чёрного ящика»: вы сохраняете модель мышления effector (события текут через граф правил) и просто получаете удобства запросов декларативно.</p><h2 id="что-вы-получаете" tabindex="-1">Что вы получаете <a class="header-anchor" href="#что-вы-получаете" aria-label="Permalink to &quot;Что вы получаете&quot;">​</a></h2><ul><li><strong>Статусы и жизненный цикл</strong> — <code>$data / $error / $status / $pending</code>, <code>finished.{done,fail}</code>.</li><li><strong>Конкурентность</strong> — <code>TAKE_LATEST</code> (по умолчанию), <code>TAKE_FIRST</code>, <code>TAKE_EVERY</code>; гонки просто исчезают.</li><li><strong>Ретраи</strong> — на уровне графа, каждая попытка — реальный вызов эффекта.</li><li><strong>Кэш</strong> — staleAfter, SWR, сборка мусора, дедупликация, персист.</li><li><strong>Реальная отмена</strong> — прерывание запроса, а не просто игнор результата.</li><li><strong>Мутации и инвалидация</strong> — <code>createMutation</code>, <code>invalidate</code>, <code>update</code>, оптимистичные апдейты.</li><li><strong>Валидация</strong> — контракты-схемы (zod / Standard Schema) превращают плохой ответ в ошибку.</li><li><strong>Декларативный HTTP</strong> — <code>createJsonQuery</code> поверх глобального <code>fetch</code>.</li><li><strong>Пагинация</strong> — <code>createInfiniteQuery</code>.</li><li><strong>Биндинги</strong> — <code>useUnit(query)</code> в React и Vue.</li></ul><h2 id="философия" tabindex="-1">Философия <a class="header-anchor" href="#философия" aria-label="Permalink to &quot;Философия&quot;">​</a></h2><ul><li><strong>Дружелюбно по умолчанию, мощно внутри.</strong> Inline-опции покрывают 90%; те же возможности — отдельные операторы для остального.</li><li><strong>Без магии.</strong> Это обычные юниты effector (<code>createStore</code> / <code>sample</code> / <code>createEffect</code>), которые вы могли бы написать сами — просто собранные за вас.</li><li><strong>Честно.</strong> Мы говорим, когда это <em>не</em> нужно, и как оно соотносится с <a href="/effector-query/ru/guide/vs-farfetched">farfetched</a>.</li></ul><p>Готовы? <a href="/effector-query/ru/guide/getting-started">К быстрому старту →</a></p>`,14)])])}const g=i(r,[["render",o]]);export{k as __pageData,g as default};
